    ui.bindAttr(inp, placeholder, 'placeholder')
    ui.bindAttr(inp, disabled, 'disabled')
    ui.bindAttr(btn, disabled, 'disabled')
    ui.bind(el, sig, function (v) { if (document.activeElement !== inp) inp.value = v || '' })
